'use client'

import type { ImageRef } from '@/types/content'
import { cn } from '@/utilities/ui'
import NextImage from 'next/image'
import React from 'react'

// Base64 blur placeholder (inherited from old Payload Media component).
const placeholderBlur =
  'data:image/png;base64,'

interface Props {
  resource?: ImageRef | null
  className?: string
  imgClassName?: string
  pictureClassName?: string
  fill?: boolean
  priority?: boolean
  loading?: 'lazy' | 'eager'
  sizes?: string
  onClick?: () => void
}

export const Media: React.FC<Props> = ({
  resource,
  className,
  imgClassName,
  pictureClassName,
  fill,
  priority,
  loading: loadingFromProps,
  sizes,
  onClick,
}) => {
  if (!resource) return null

  const loading = loadingFromProps || (!priority ? 'lazy' : undefined)

  // Reasonable default sizes so Next/Image requests appropriately-sized variants.
  const imgSizes = sizes || '(max-width: 768px) 100vw, (max-width: 1200px) 75vw, 50vw'

  return (
    <picture className={cn(pictureClassName, className)} onClick={onClick}>
      <NextImage
        alt={resource.alt}
        className={cn(imgClassName)}
        fill={fill}
        height={!fill ? resource.height : undefined}
        width={!fill ? resource.width : undefined}
        placeholder="blur"
        blurDataURL={placeholderBlur}
        priority={priority}
        loading={loading}
        sizes={imgSizes}
        src={resource.src}
      />
    </picture>
  )
}
